## WebSocket API - Authentication

### Login with Username and Password

```javascript
const io = require("socket.io-client");
const socket = io("http://localhost:3001");

// Login without 2FA
socket.emit("login", {
  username: "admin",
  password: "secretpassword"
}, (response) => {
  if (response.ok) {
    console.log("JWT Token:", response.token);
    // Store token for future connections
  } else if (response.tokenRequired) {
    console.log("2FA token required");
    // Prompt for 2FA token
  } else {
    console.error("Login failed:", response.msg);
  }
});

// Login with 2FA
socket.emit("login", {
  username: "admin",
  password: "secretpassword",
  token: "123456"  // 6-digit TOTP token
}, (response) => {
  if (response.ok) {
    console.log("Login successful with 2FA");
    console.log("JWT Token:", response.token);
  } else {
    console.error("Login failed:", response.msg);
  }
});
```

### Login with JWT Token

```javascript
// Reconnect using saved JWT token
socket.emit("loginByToken", "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9...", (response) => {
  if (response.ok) {
    console.log("Authenticated successfully");
  } else {
    console.error("Token invalid or expired");
  }
});
```

### Setup Initial Admin Account

```javascript
// Check if setup is needed
socket.emit("needSetup", (response) => {
  if (response.needSetup) {
    // Perform initial setup
    socket.emit("setup", "admin", "strongpassword123", (setupResponse) => {
      if (setupResponse.ok) {
        console.log("Setup complete, admin account created");
      } else {
        console.error("Setup failed:", setupResponse.msg);
      }
    });
  } else {
    console.log("Setup already completed");
  }
});
```

## WebSocket API - Monitor Management

### Create New Monitor

```javascript
// Create HTTP monitor with notifications
socket.emit("add", {
  type: "http",
  name: "Production API",
  url: "https://api.example.com/health",
  method: "GET",
  interval: 60,  // Check every 60 seconds
  maxretries: 3,
  timeout: 30,
  active: true,
  ignoreTls: false,
  upsideDown: false,
  accepted_statuscodes: ["200-299"],
  expiryNotification: true,
  notificationIDList: [1, 2],  // Discord and email notifications
  description: "Main production API health check",
  tags: [
    { tag_id: 1, value: "production" }
  ]
}, (response) => {
  if (response.ok) {
    console.log("Monitor created with ID:", response.monitorID);
  } else {
    console.error("Failed to create monitor:", response.msg);
  }
});

// Create Push monitor
socket.emit("add", {
  type: "push",
  name: "External Service Push",
  interval: 60,
  maxretries: 1,
  active: true
}, (response) => {
  if (response.ok) {
    console.log("Push monitor created");
    console.log("Push URL:", `http://localhost:3001/api/push/${response.pushToken}`);
  }
});

// Create Docker container monitor
socket.emit("add", {
  type: "docker",
  name: "Nginx Container",
  docker_container: "nginx-web",
  docker_host: 1,  // Docker host ID
  interval: 60,
  active: true
}, (response) => {
  if (response.ok) {
    console.log("Docker monitor created:", response.monitorID);
  }
});
```

### Update Existing Monitor

```javascript
// Update monitor configuration
socket.emit("editMonitor", {
  id: 5,
  name: "Production API (Updated)",
  url: "https://api.example.com/v2/health",
  interval: 30,  // Changed to 30 seconds
  notificationIDList: [1, 2, 3],  // Added third notification
  accepted_statuscodes: ["200-299", "304"]
}, (response) => {
  if (response.ok) {
    console.log("Monitor updated successfully");
  } else {
    console.error("Update failed:", response.msg);
  }
});
```

### Pause and Resume Monitor

```javascript
// Pause monitoring
socket.emit("pauseMonitor", 5, (response) => {
  if (response.ok) {
    console.log("Monitor paused");
  }
});

// Resume monitoring
socket.emit("resumeMonitor", 5, (response) => {
  if (response.ok) {
    console.log("Monitor resumed");
  }
});
```

### Delete Monitor

```javascript
// Permanently delete monitor
socket.emit("deleteMonitor", 5, (response) => {
  if (response.ok) {
    console.log("Monitor deleted successfully");
  } else {
    console.error("Delete failed:", response.msg);
  }
});
```

### Fetch Monitor List

```javascript
// Get all monitors for authenticated user
socket.emit("getMonitorList", (response) => {
  console.log("Total monitors:", Object.keys(response).length);
  Object.values(response).forEach(monitor => {
    console.log(`${monitor.id}: ${monitor.name} - ${monitor.type} - Active: ${monitor.active}`);
  });
});
```

### Fetch Monitor Heartbeat History

```javascript
// Get heartbeat history for specific period
socket.emit("getMonitorBeats", 5, 24, (response) => {
  console.log("Heartbeats for last 24 hours:", response.length);
  response.forEach(beat => {
    console.log(`Time: ${beat.time}, Status: ${beat.status}, Ping: ${beat.ping}ms, Message: ${beat.msg}`);
  });
});
```

### Listen for Real-Time Heartbeat Updates

```javascript
// Listen for heartbeat events (emitted to authenticated users)
socket.on("heartbeat", (data) => {
  console.log(`Monitor ${data.monitor_id}: ${data.status === 1 ? 'UP' : 'DOWN'}`);
  console.log(`Ping: ${data.ping}ms, Time: ${data.time}`);
  console.log(`Message: ${data.msg}`);
});

// Listen for heartbeat list updates
socket.on("heartbeatList", (monitorId, heartbeats) => {
  console.log(`Received ${heartbeats.length} heartbeats for monitor ${monitorId}`);
});

// Listen for uptime updates
socket.on("uptime", (monitorId, uptimeData) => {
  console.log(`Monitor ${monitorId} uptime:`, uptimeData);
});
```

## WebSocket API - Two-Factor Authentication

### Enable 2FA for User Account

```javascript
// Step 1: Prepare 2FA (generate TOTP secret)
socket.emit("prepare2FA", "currentpassword", (response) => {
  if (response.ok) {
    console.log("2FA Secret:", response.secret);
    console.log("Scan this QR code with your authenticator app:");
    console.log(response.uri);
  } else {
    console.error("Failed to prepare 2FA:", response.msg);
  }
});

// Step 2: Verify TOTP token from authenticator app
socket.emit("verifyToken", "123456", "currentpassword", (response) => {
  if (response.valid) {
    console.log("Token is valid, proceed to enable 2FA");
  } else {
    console.log("Token is invalid");
  }
});

// Step 3: Save/Enable 2FA
socket.emit("save2FA", "currentpassword", (response) => {
  if (response.ok) {
    console.log("2FA enabled successfully");
  } else {
    console.error("Failed to enable 2FA:", response.msg);
  }
});
```

### Disable 2FA

```javascript
// Disable 2FA for current user
socket.emit("disable2FA", "currentpassword", (response) => {
  if (response.ok) {
    console.log("2FA disabled successfully");
  } else {
    console.error("Failed to disable 2FA:", response.msg);
  }
});
```

### Check 2FA Status

```javascript
// Get current 2FA status
socket.emit("twoFAStatus", (response) => {
  console.log("2FA Status:", response.status);  // true or false
});
```

