## WebSocket API - Tag Management

### Create and Manage Tags

```javascript
// Create new tag
socket.emit("addTag", {
  name: "production",
  color: "#5CDD8B"
}, (response) => {
  if (response.ok) {
    console.log("Tag created with ID:", response.tag.id);
  }
});

// Edit tag
socket.emit("editTag", {
  id: 1,
  name: "production-critical",
  color: "#FF0000"
}, (response) => {
  if (response.ok) {
    console.log("Tag updated");
  }
});

// Associate tag with monitor
socket.emit("addMonitorTag", 1, 5, "v2.0", (response) => {
  // tagID=1, monitorID=5, value="v2.0"
  if (response.ok) {
    console.log("Tag added to monitor");
  }
});

// Update monitor tag value
socket.emit("editMonitorTag", 1, 5, "v2.1", (response) => {
  if (response.ok) {
    console.log("Monitor tag updated");
  }
});

// Remove tag from monitor
socket.emit("deleteMonitorTag", 1, 5, "v2.1", (response) => {
  if (response.ok) {
    console.log("Tag removed from monitor");
  }
});

// Get all tags
socket.emit("getTags", (response) => {
  console.log("Available tags:");
  response.tags.forEach(tag => {
    console.log(`${tag.id}: ${tag.name} (${tag.color})`);
  });
});
```

## WebSocket API - Maintenance Windows

### Create Maintenance Window

```javascript
// Create one-time maintenance window
socket.emit("addMaintenance", {
  title: "Database Upgrade",
  description: "PostgreSQL version upgrade",
  strategy: "single",
  active: true,
  dateRange: [
    "2025-10-30 02:00:00",
    "2025-10-30 06:00:00"
  ],
  timeRange: [
    { hours: 2, minutes: 0 },
    { hours: 6, minutes: 0 }
  ]
}, (response) => {
  if (response.ok) {
    console.log("Maintenance window created:", response.maintenanceID);
  }
});

// Create recurring maintenance window
socket.emit("addMaintenance", {
  title: "Weekly Backup",
  description: "Automated database backup",
  strategy: "recurring-interval",
  active: true,
  intervalDay: 7,  // Every 7 days
  dateRange: [
    "2025-10-29 00:00:00",
    "2025-12-31 23:59:59"
  ],
  timeRange: [
    { hours: 3, minutes: 0 },
    { hours: 4, minutes: 0 }
  ]
}, (response) => {
  if (response.ok) {
    console.log("Recurring maintenance created");
  }
});
```

### Associate Monitors with Maintenance

```javascript
// Add monitors to maintenance window
socket.emit("addMonitorMaintenance", 1, [5, 6, 7], (response) => {
  // maintenanceID=1, monitors=[5,6,7]
  if (response.ok) {
    console.log("Monitors added to maintenance window");
  }
});

// Add status pages to maintenance window
socket.emit("addMaintenanceStatusPage", 1, [1, 2], (response) => {
  // maintenanceID=1, statusPages=[1,2]
  if (response.ok) {
    console.log("Status pages added to maintenance window");
  }
});
```

### Pause and Resume Maintenance

```javascript
// Pause maintenance window
socket.emit("pauseMaintenance", 1, (response) => {
  if (response.ok) {
    console.log("Maintenance paused");
  }
});

// Resume maintenance window
socket.emit("resumeMaintenance", 1, (response) => {
  if (response.ok) {
    console.log("Maintenance resumed");
  }
});
```

## WebSocket API - Status Pages

### Create and Configure Status Page

```javascript
// Create new status page
socket.emit("addStatusPage", "Service Status", "services", (response) => {
  // title, slug
  if (response.ok) {
    console.log("Status page created");
  }
});

// Save status page configuration
socket.emit("saveStatusPage", "services", {
  id: 1,
  slug: "services",
  title: "Service Status",
  description: "Real-time status of all services",
  theme: "light",
  published: true,
  showTags: true,
  domainNameList: ["status.example.com"],
  googleAnalyticsId: "UA-12345678-1",
  customCSS: ".monitor { font-size: 16px; }",
