## Docker and Proxy Configuration

### Configure Docker Host

```javascript
// Add Docker host connection
socket.emit("addDockerHost", {
  name: "Production Docker Host",
  dockerType: "tcp",
  dockerDaemon: "tcp://192.168.1.100:2375"
}, null, (response) => {
  if (response.ok) {
    console.log("Docker host added:", response.id);
  }
});

// Add Docker socket connection
socket.emit("addDockerHost", {
  name: "Local Docker",
  dockerType: "socket",
  dockerDaemon: "/var/run/docker.sock"
}, null, (response) => {
  if (response.ok) {
    console.log("Docker host added");
  }
});

// Test Docker host connectivity
socket.emit("testDockerHost", {
  dockerType: "tcp",
  dockerDaemon: "tcp://192.168.1.100:2375"
}, (response) => {
  if (response.ok) {
    console.log("Docker host connection successful");
